INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-01', 'Control hiring demand conversion into approved requisition launch evidence', 'Ability to convert manager headcount demand into a budget-checked, approval-routed, ATS-ready requisition that can be launched with evidence of role criteria, ownership, and approval status.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-02', 'Screen candidate profiles against requisition criteria and document interview-readiness decisions', 'Ability to review candidate evidence, apply eligibility and role criteria, distinguish exceptions, and produce a documented screening decision for hiring-manager review.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-03', 'Configure structured interview plans and close scorecard evidence for selection decisions', 'Ability to translate role criteria into interview stages, evaluator assignments, scorecards, completion tracking, and decision-ready interview evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-04', 'Prepare finalist offer handoff and close hiring outcome evidence', 'Ability to consolidate finalist selection evidence, compensation and joining inputs, approval artifacts, candidate response, and onboarding handoff data for hiring closure.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-05', 'Deploy external workers from staffing order through first-shift confirmation', 'Ability to translate client staffing demand into worker matching, compliance checks, assignment confirmation, client communication, and first-shift deployment evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-06', 'Control temporary assignment extension, replacement, or closure decisions', 'Ability to review assignment performance, client decision, worker notice, timesheet/billing impacts, and closure evidence for temporary workforce transitions.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-07', 'Administer EOR worker setup from country checks to onboarding completion', 'Ability to assemble worker and country-specific employment evidence, configure EOR records, route contract/payroll/benefits handoffs, and confirm local onboarding completion.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-08', 'Process EOR payroll and benefit changes with country-specific compliance handoff', 'Ability to assess EOR employment change implications, collect approvals, update employment/payroll/benefit records, and produce compliant handoff evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-09', 'Validate payroll cycle inputs through pre-release payroll control evidence', 'Ability to load payroll inputs, reconcile master and time data, run calculation checks, resolve release blockers, and lock a disbursement-ready payroll batch.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-10', 'Correct payroll exceptions through variance diagnosis, recalculation, and approval evidence', 'Ability to trace payroll variances to source inputs, execute authorized corrections, recalculate employee and statutory impact, and submit corrected registers for approval.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-11', 'Update benefits eligibility and enrollment evidence from employee lifecycle events', 'Ability to identify benefits-triggering events, verify eligibility and dependent evidence, update election/provider records, and retain enrollment proof.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-12', 'Prepare statutory contribution filings with wage-base calculation and audit evidence', 'Ability to extract statutory wage and identifier data, calculate contributions, reconcile challans or filings, resolve mismatches, and retain filing acknowledgements.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-13', 'Close employee master-data changes with HRIS evidence and downstream controls', 'Ability to validate employee data change requests, update HRIS records with proof and effective dates, monitor downstream impacts, and close audit-ready HR data cases.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-14', 'Administer joiner-mover-leaver checklists through service-owner closure evidence', 'Ability to trigger lifecycle checklists, verify documents and owner tasks, coordinate access/assets/payroll handoffs, and close JML cases with completion evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-15', 'Resolve employee HR service cases using policy evidence and service-level controls', 'Ability to classify employee HR inquiries, apply knowledge-base and eligibility rules, escalate sensitive cases, document resolution, and close employee communications.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-16', 'Restore ATS-HRIS data synchronization through field-mapping diagnosis and reconciliation', 'Ability to diagnose recruiting-to-HRIS integration failures, compare payload and mapping values, correct records or interface issues, and confirm restored data sync.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-17', 'Translate manager people-advisory requests into risk-aware action plans', 'Ability to assess manager people issues using employee, policy, performance, and risk evidence, recommend action plans, and close advisory cases with residual-risk handoff where needed.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-18', 'Support organization change communication using impact mapping and people-risk controls', 'Ability to map affected employee groups, identify change risks, prepare communication packs, route approvals, and archive release evidence and follow-up actions.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-19', 'Build workforce gap registers from demand forecasts and headcount assumptions', 'Ability to standardize workforce baseline data, compare forecast demand to supply and pipeline assumptions, and publish gap registers with owners and review dates.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-20', 'Translate workforce scenarios into accountable people-action handoffs', 'Ability to model workforce scenario impacts, evaluate cost/skill/timing trade-offs, prioritize actions, and hand off accountable workforce plans with risk monitoring.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-21', 'Convert training needs evidence into prioritized learning briefs', 'Ability to collect performance and business-change signals, validate task gaps with managers or SMEs, define audience/output requirements, and produce prioritized learning briefs.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-22', 'Operate learning program setup through LMS completion and evidence closure', 'Ability to configure LMS programs, enroll learners, monitor completion and exceptions, issue completion evidence, and archive learner/program records.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-23', 'Run performance cycle setup through review completion evidence', 'Ability to configure performance cycles, validate participant and approver data, monitor review completion and exceptions, and close archived performance evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-24', 'Convert engagement survey insights into manager action follow-up evidence', 'Ability to analyze survey results, identify priority themes and confidentiality risks, create manager action plans, monitor follow-up, and close action evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-25', 'Resolve employee grievances through severity classification, evidence review, and outcome closure', 'Ability to log grievances, classify risk and escalation paths, collect supporting evidence, assess policy alignment, and close resolution recommendations with communication and retention evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-26', 'Manage workplace investigation cases through evidence control and corrective-action handoff', 'Ability to create investigation cases, define evidence and interview plans, manage risk controls, synthesize findings, and hand off corrective actions with restricted records.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-27', 'Complete background screening decisions using consent, verification, and adjudication evidence', 'Ability to order background checks, validate candidate authorization and data, manage vendor discrepancies, apply adjudication rules, and retain hiring decision evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('HR-IND-CAP-28', 'Close exit and offboarding cases with payroll, access, asset, and transition evidence', 'Ability to record exit events, coordinate checklist owners, manage final pay and access/asset tasks, capture exit insight or transition support, and close retained evidence.', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.occupations (code, name, description, primary_riasec, secondary_riasec, tertiary_riasec, riasec_code_string, riasec_reason, observable_behaviours, is_active) VALUES ('HR-ROLE-001', 'HR Specialist', 'HR/workforce pathway work for Control hiring demand conversion into approved requisition launch evidence, using bridge area ''Hiring demand intake evidence and requisition readiness practice'' and syllabus topic ''Human resource planning, job analysis, recruitment, selection, and induction'' as planning context.', 'C', 'S', 'E', 'CSE', 'Control hiring demand conversion into approved requisition launch evidence has a Conventional fit because the work depends on structured HR records, process discipline, evidence checking, workflow handoffs, and accurate closure around Hiring demand intake evidence and requisition readiness practice.; Screen candidate profiles against requisition criteria and document interview... has an Investigative fit because the work requires analysis of HR evidence, diagnosis of mismatches or risk signals, interpretation of data or policy, and reasoned decisions around Candidate evidence screening and interview-readiness decision practice.; Control hiring demand conversion into approved requisition launch evidence has a Conventional fit because the work depends on structured HR records, process discipline, evidence checking, workflow handoffs, and accurate closure around Job requirement conversion into approved requisition evidence.; Screen candidate profiles against requisition criteria and document interview... has an Investigative fit because the work requires analysis of HR evidence, diagnosis of mismatches or risk signals, interpretation of data or policy, and reasoned decisions around Structured candidate screening and selection decision documentation.; Prepare finalist offer handoff and close hiring outcome evidence has a Conventional fit because the work depends on structured HR records, process discipline, evidence checking, workflow handoffs, and accurate closure around Finalist offer handoff and joining-input evidence preparation.; Screen candidate profiles against requisition criteria and document interview... has an Investigative fit because the work requires analysis of HR evidence, diagnosis of mismatches or risk signals, interpretation of data or policy, and reasoned decisions around Evidence-based candidate screening and interview-readiness exception handling.; Configure structured interview plans and close scorecard evidence for selecti... has a Social fit because the work involves advising, supporting, explaining, resolving employee or candidate needs, and guiding stakeholders through Structured interview plan and scorecard evidence practice.', NULL, TRUE);
